mapper.update:
UPDATE recommendation_logs
user_id = #{userId}, post_id = #{postId}, scene = #{scene}, score = #{score}, rank_pos = #{rankPos}, is_clicked = #{isClicked}, created_at = #{createdAt},
WHERE id = #{id}

mapper.select:
SELECT id, user_id, post_id, scene, score, rank_pos, is_clicked, created_at
FROM recommendation_logs
WHERE user_id = #{userId}
  AND post_id = #{postId}
  AND scene = #{scene}
ORDER BY created_at DESC, id DESC
LIMIT 1

SELECT COUNT(1)
FROM recommendation_logs
WHERE created_at >= #{start}
